import { useState, useEffect, useCallback } from 'react'
import { useUser, MOCK_USERS } from '@/store';
import { PostsAPI, Notification } from '@/lib/api/posts'
import { Button } from '@/components/ui/button'
import { Badge } from '@/components/ui/badge'
import {
  DropdownMenu,
  DropdownMenuContent,
  DropdownMenuItem,
  DropdownMenuTrigger,
  DropdownMenuSeparator,
} from '@/components/ui/dropdown-menu'
import { Bell, Heart, MessageCircle, UserPlus, AtSign } from 'lucide-react'
import { format } from 'date-fns'

export default function NotificationBell() {
  const { user } = useUser()
  const [notifications, setNotifications] = useState<Notification[]>([])
  const [unreadCount, setUnreadCount] = useState(0)
  const [isLoading, setIsLoading] = useState(false)

  // Stable callback so effect dependencies remain stable
  const loadNotifications = useCallback(async () => {
    if (!user) return

    try {
      setIsLoading(true)
      const data = await PostsAPI.getNotifications(user.id)
      setNotifications(data)
      setUnreadCount(data.filter(n => !n.read).length)
    } catch (error) {
      console.error('Error loading notifications:', error)
    } finally {
      setIsLoading(false)
    }
  }, [user])

  useEffect(() => {
    if (user) {
      loadNotifications()
      // Poll for new notifications every 30 seconds
      const interval = setInterval(loadNotifications, 30000)
      return () => clearInterval(interval)
    }
  }, [user, loadNotifications])

  const markAsRead = async (notificationId: string) => {
    try {
      await PostsAPI.markNotificationAsRead(notificationId)
      setNotifications(prev =>
        prev.map(n =>
          n.id === notificationId ? { ...n, read: true } : n
        )
      )
      setUnreadCount(prev => Math.max(0, prev - 1))
    } catch (error) {
      console.error('Error marking notification as read:', error)
    }
  }

  const getNotificationIcon = (type: Notification['type']) => {
    switch (type) {
      case 'like':
        return <Heart className="h-4 w-4 text-red-500" />
      case 'comment':
        return <MessageCircle className="h-4 w-4 text-blue-500" />
      case 'follow':
        return <UserPlus className="h-4 w-4 text-green-500" />
      case 'mention':
        return <AtSign className="h-4 w-4 text-purple-500" />
      default:
        return <Bell className="h-4 w-4 text-gray-500" />
    }
  }

  const getNotificationText = (notification: Notification) => {
    switch (notification.type) {
      case 'like':
        return 'liked your post'
      case 'comment':
        return 'commented on your post'
      case 'follow':
        return 'started following you'
      case 'mention':
        return 'mentioned you in a post'
      default:
        return 'sent you a notification'
    }
  }

  if (!user) return null

  return (
    <DropdownMenu>
      <DropdownMenuTrigger asChild>
        <Button variant="ghost" size="icon" className="relative">
          <Bell className="h-5 w-5" />
          {unreadCount > 0 && (
            <Badge
              variant="destructive"
              className="absolute -top-1 -right-1 h-5 w-5 flex items-center justify-center p-0 text-xs"
            >
              {unreadCount > 99 ? '99+' : unreadCount}
            </Badge>
          )}
        </Button>
      </DropdownMenuTrigger>
      <DropdownMenuContent align="end" className="w-80 max-h-96 overflow-y-auto">
        <div className="px-2 py-1.5 text-sm font-medium border-b">
          Notifications
        </div>

        {isLoading ? (
          <div className="px-2 py-4 text-center text-sm text-gray-500">
            Loading...
          </div>
        ) : notifications.length === 0 ? (
          <div className="px-2 py-4 text-center text-sm text-gray-500">
            No notifications yet
          </div>
        ) : (
          notifications.map((notification) => (
            <DropdownMenuItem
              key={notification.id}
              className={`px-2 py-3 cursor-pointer ${
                !notification.read ? 'bg-blue-50' : ''
              }`}
              onClick={() => markAsRead(notification.id)}
            >
              <div className="flex items-start gap-3 w-full">
                <div className="flex-shrink-0 mt-0.5">
                  {getNotificationIcon(notification.type)}
                </div>
                <div className="flex-1 min-w-0">
                  <p className="text-sm text-gray-900">
                    Someone {getNotificationText(notification)}
                  </p>
                  <p className="text-xs text-gray-500 mt-1">
                    {format(new Date(notification.created_at), 'MMM d, h:mm a')}
                  </p>
                </div>
                {!notification.read && (
                  <div className="flex-shrink-0">
                    <div className="h-2 w-2 bg-blue-500 rounded-full"></div>
                  </div>
                )}
              </div>
            </DropdownMenuItem>
          ))
        )}

        {notifications.length > 0 && (
          <>
            <DropdownMenuSeparator />
            <div className="px-2 py-1.5">
              <Button
                variant="ghost"
                size="sm"
                className="w-full text-xs"
                onClick={() => {
                  // Mark all as read
                  notifications
                    .filter(n => !n.read)
                    .forEach(n => markAsRead(n.id))
                }}
              >
                Mark all as read
              </Button>
            </div>
          </>
        )}
      </DropdownMenuContent>
    </DropdownMenu>
  )
}

import { useState, useRef, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { Send, Sparkles, Mic, MicOff } from 'lucide-react';
import SpeechRecognition, { useSpeechRecognition } from 'react-speech-recognition';
import { callGemini } from '@/lib/geminiClient';
import { Input } from '@/components/ui/input';

interface ChatWindowProps {
  compact?: boolean;
}

interface Message {
  id: string;
  role: 'user' | 'assistant';
  content: string;
}

const STATIC_ANSWERS: Record<string, string> = {
  "What is PM-KISAN?":
    "PM-KISAN gives ₹6,000/year directly to farmer families in 3 instalments. Apply at your nearest Common Service Centre with Aadhaar and land records.",
  "Best crops for Kharif season?":
    "For Karnataka Kharif: Cotton, Ragi, Maize, Soybean, and Groundnut. Cotton suits Black Cotton soil districts like Bagalkot and Bidar.",
  "How to improve soil health?":
    "Apply organic matter (compost/FYM) before sowing. Test soil pH — 6.5 to 7.5 is ideal. Use Urea for nitrogen, DAP for phosphorus at planting.",
  "Cotton price today?":
    "Check the Market Prices page for live APMC rates. Current MSP for cotton is ₹6,620/quintal as set by the Government of India.",
};

export function ChatWindow({ compact = false }: ChatWindowProps) {
  const [input, setInput] = useState('');
  const [sending, setSending] = useState(false);
  const [messages, setMessages] = useState<Message[]>([
    {
      id: 'welcome',
      role: 'assistant',
      content: 'Namaste! I am KrishiMitra, your farming assistant. How can I help you today?',
    },
  ]);
  const listRef = useRef<HTMLDivElement | null>(null);

  const {
    transcript,
    listening,
    resetTranscript,
    browserSupportsSpeechRecognition,
  } = useSpeechRecognition();

  useEffect(() => {
    if (transcript) {
      setInput(transcript);
    }
  }, [transcript]);

  useEffect(() => {
    if (listRef.current) {
      listRef.current.scrollTop = listRef.current.scrollHeight;
    }
  }, [messages, sending]);

  const handleSend = async (textToSend?: string) => {
    const query = (textToSend || input).trim();
    if (!query) return;

    const userMsg: Message = {
      id: Math.random().toString(),
      role: 'user',
      content: query,
    };

    setMessages(prev => [...prev, userMsg]);
    setInput('');
    resetTranscript();
    setSending(true);

    try {
      const staticReply = STATIC_ANSWERS[query];
      let replyText = '';

      if (staticReply) {
        replyText = staticReply;
      } else {
        const historyContext = messages.map(m => ({
          role: m.role,
          content: m.content,
        }));
        replyText = await callGemini(query, undefined, historyContext);
      }

      setMessages(prev => [
        ...prev,
        {
          id: Math.random().toString(),
          role: 'assistant',
          content: replyText,
        },
      ]);
    } catch (error: any) {
      setMessages(prev => [
        ...prev,
        {
          id: Math.random().toString(),
          role: 'assistant',
          content: error.message || 'I am having trouble responding right now. Please try again.',
        },
      ]);
    } finally {
      setSending(false);
    }
  };

  const toggleListening = () => {
    if (listening) {
      SpeechRecognition.stopListening();
    } else {
      resetTranscript();
      SpeechRecognition.startListening({ continuous: true });
    }
  };

  return (
    <div className="flex flex-col h-full bg-[#1a1a14] text-[#f0ece0]">
      {/* Scrollable Message List */}
      <div 
        ref={listRef} 
        className="flex-1 overflow-y-auto p-4 space-y-4 custom-scrollbar text-[13px]"
      >
        {messages.map((m) => (
          <div key={m.id} className={`flex ${m.role === 'user' ? 'justify-end' : 'justify-start'}`}>
            <div className={`max-w-[85%] rounded-xl px-3 py-2 leading-relaxed shadow-sm ${
              m.role === 'user'
                ? 'bg-[#c49a2a] text-[#0f0f0b] rounded-tr-none font-medium'
                : 'bg-neutral-900 border border-neutral-800 text-[#e2dcd0] rounded-tl-none'
            }`}>
